import { Component, OnInit, Inject } from '@angular/core';
import { FormBuilder, FormGroup, Validators as val } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material';

import moment from 'moment';

import { CycleService } from 'app/core/cycle.service';
import { SnackbarService } from 'app/core/snackbar.service';

@Component({
  selector: 'ctb-change-cycle-end-modal',
  template: `

    <form [formGroup]="form" (submit)="onSubmit(form)">

      <h3 mat-dialog-title>Change Subscription Expiration</h3>

      <mat-dialog-content>

        <div class="form-group center-block">
          <input formControlName="date" matInput [matDatepicker]="picker">
          <mat-datepicker-toggle matSuffix [for]="picker"></mat-datepicker-toggle>
          <mat-datepicker #picker></mat-datepicker>
        </div>

      </mat-dialog-content>

      <mat-dialog-actions>

        <button mat-button mat-dialog-close
            class="btn z-depth-0 waves-effect waves-light blue-grey lighten-5 blue-grey-text left" (click)="cancel()"
            type="submit">
          Cancel
        </button>

        <ctb-loader class="right" classes="small" *ngIf="formIsLoading"></ctb-loader>
        <button mat-button type="submit" [disabled]="formIsLoading" class="waves-effect waves-light btn right right">
          Save
        </button>
      </mat-dialog-actions>
    </form>
  `,
  styles: [`
      .form-group {
          position: relative;
      }
      mat-datepicker-toggle {
          position: absolute;
          top: 0;
          right: 0; 
      }
  `],
})
export class ChangeCycleEndModalComponent implements OnInit {

  formIsLoading: boolean;
  form: FormGroup;

  constructor(
    public dialogRef: MatDialogRef<ChangeCycleEndModalComponent>,
    private fb: FormBuilder,
    private cycleService: CycleService,
    private snackbar: SnackbarService,
    @Inject(MAT_DIALOG_DATA) public data: any,
  ) {
    this.form = fb.group({
      date: [data.cycle.ends_on, [val.required]],
    });
  }

  ngOnInit() {
  }

  cancel() {
    this.dialogRef.close();
  }

  onNoClick(): void {
    this.cancel();
  }

  onSubmit(form) {
    if (form.invalid) return false;
    this.formIsLoading = true;

    const ends_on = moment(form.value.date).format('YYYY-MM-DD');

    this.cycleService.update(this.data.cycle.id, { ends_on })
        .subscribe(
            cycle => {
              this.formIsLoading = false;
              this.snackbar.snack('Updated Subscription Expiration.');
              this.dialogRef.close({ cycle });
            },
            err => {
              console.error(err);
              this.formIsLoading = false;
              this.snackbar.error('Something went wrong.');
            }
        );
  }

}



