import { Component, OnInit, ViewChild } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';

import { Observable } from 'rxjs/Observable';

import { Subscription } from 'models/subscription';
import { CycleService } from 'app/core/cycle.service';
import { SubscriptionService } from 'app/core/subscription.service';
import { SnackbarService } from 'app/core/snackbar.service';
import { CreateAddonModalComponent } from './create-addon-modal/create-addon-modal.component';
import { MatDialog } from '@angular/material';
import { ChangeCycleEndModalComponent } from './change-cycle-end-modal.component';

@Component({
  selector: 'ctb-subscription',
  templateUrl: './subscription.component.html',
  styleUrls: ['./subscription.component.scss']
})
export class SubscriptionComponent implements OnInit {

  subId: number;
  sub$: Observable<Subscription>;
  sub: Subscription;
  showPastCycles: boolean;
  loadingMarkPaid: boolean;

  constructor(
      private cycleService: CycleService,
      private subscriptionService: SubscriptionService,
      private route: ActivatedRoute,
      private router: Router,
      private snackbar: SnackbarService,
      private dialog: MatDialog,
  ) {
    this.router.onSameUrlNavigation = 'reload';
    this.router.routeReuseStrategy.shouldReuseRoute = () => false;
  }

  ngOnInit() {

    this.route.params.subscribe(params => {
      this.subId = params.id;

      this.sub$ = this.subscriptionService.get(this.subId)
          .map(sub => {
            console.log(sub);
             this.showPastCycles = !sub.cycle;
             if (sub.inactiveCycles) {
               sub.inactiveCycles.forEach(c => {
                 c.isPending = !c.starts_on && !c.ends_on;
               });
             }
             this.sub = sub;
             return sub;
          })
          .share();
    });
  }

  markPaid(cycle) {
    this.loadingMarkPaid = true;
    this.cycleService.markPaid(cycle.id)
        .subscribe(
            res => {
              this.loadingMarkPaid = false;
              this.router.navigateByUrl(this.router.url);
              this.snackbar.snack('Subscription is now activate.');
            },
            err => {
              this.loadingMarkPaid = false;
              this.snackbar.error('Something went wrong.');
            }
        );
  }

  updateCycleEnd() {
    const dialogRef = this.dialog.open(ChangeCycleEndModalComponent, {
      // height: '240px',
      width: '400px',
      data: { cycle: this.sub.cycle },
    });

    dialogRef.afterClosed()
        .subscribe(({ cycle }) => Object.assign(this.sub.cycle, cycle) );
  }


  createAddon() {
    const dialogRef = this.dialog.open(CreateAddonModalComponent, {
      // height: '240px',
      width: '400px',
      data: { subscriptionId: this.subId },
    });

  }


}



