import { NgModule } from '@angular/core';
import { SubscriptionsComponent } from './subscriptions.component';
import { SharedModule } from 'app/shared/shared.module';
import { RouterModule } from '@angular/router';
import { SubscriptionComponent } from './subscription/subscription.component';
import { CreateAddonModalComponent } from './subscription/create-addon-modal/create-addon-modal.component';
import { ChangeCycleEndModalComponent } from './subscription/change-cycle-end-modal.component';

@NgModule({
  imports: [
    SharedModule,
    RouterModule.forChild([
      { path: '', component: SubscriptionsComponent },
      { path: ':id', component: SubscriptionComponent },
    ]),
  ],
  declarations: [
    SubscriptionsComponent,
    SubscriptionComponent,
    CreateAddonModalComponent,
    ChangeCycleEndModalComponent
  ],
  entryComponents: [
    CreateAddonModalComponent,
    ChangeCycleEndModalComponent,
  ],
})
export class SubscriptionsModule {
}



